def shorthash_to_words(sh):
	hashvalue = int(sh, 16)
	word_3 = nouns[hashvalue % len(nouns)]
	hashvalue = int(hashvalue / len(nouns))
	word_1 = adjectives_a[hashvalue % len(adjectives_a)]
	hashvalue = int(hashvalue / len(adjectives_a))
	word_2 = adjectives_b[hashvalue]
	return [word_1, word_2, word_3]

def words_to_shorthash(a, b, c):
	word_3 = nouns.index(c)
	word_1 = adjectives_a.index(a)
	word_2 = adjectives_b.index(b)
	hashvalue = word_3 + len(nouns) * (word_1 + len(adjectives_a) * word_2)
	return "{:07x}".format(hashvalue)

def get_git_revision_short_hash():
    return subprocess.check_output(['git', 'rev-parse', '--short', 'HEAD']).decode('ascii').strip()

def main():
	if len(sys.argv) == 1:
		words = shorthash_to_words(get_git_revision_short_hash())	
		print(words[0] + " " + words[1] + " " + words[2])
		
	if len(sys.argv) == 2:
		words = shorthash_to_words(sys.argv[1])	
		print(words[0] + " " + words[1] + " " + words[2])

	if len(sys.argv) == 4:
		print(words_to_shorthash(sys.argv[1], sys.argv[2], sys.argv[3]))	

if __name__ == "__main__":
	main()
